args.sparql:
SELECT ?winner ?winnerLabel WHERE {
  wd:Q373688 wdt:P179 ?season .
  ?season wdt:P1545 ?seasonNumber .
  FILTER (?seasonNumber = 2) .
  ?season wdt:P192 ?winner .
  SERVICE wikibase:label { bd:serviceParam wikibase:language 'en' . }
}

SELECT ?winner ?winnerLabel WHERE {
  wd:Q373688 wdt:P179 ?season .
  ?season rdfs:label ?seasonLabel .
  FILTER (LANG(?seasonLabel) = 'en') .
  FILTER (CONTAINS(UCASE(?seasonLabel), 'SERIES 2')) .
  ?season wdt:P192 ?winner .
  SERVICE wikibase:label { bd:serviceParam wikibase:language 'en' . }
}
